#include <bits/stdc++.h>
using namespace std;
const int N=1005;
int n,m,sum,u,v,cnt[N],vis[N],ans;
vector<int> g[N];
void dfs(int x)
{
	if(x==v)
	{
		sum++;
		for(int i=1;i<=n;i++)
		{
			if(vis[i]) cnt[i]++;
		}
		return ;
	}
	for(int i=0;i<g[x].size();i++)
	{
		int nxt=g[x][i];
		if(vis[nxt]==0)
		{
			vis[nxt]=1;
			dfs(nxt);
			vis[nxt]=0;
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	cin>>u>>v;
	dfs(u);
	if(sum==0)
	{
		cout<<-1;
		return 0;
	}
	for(int i=1;i<=n;i++)
	{
		if(cnt[i]==sum) ans++;
	}
	cout<<ans-1;
	return 0;
}
